export type UpdatePreferencesMutationResult = NonNullable<
  Awaited<ReturnType<typeof updatePreferences>>
>;
export type UpdatePreferencesMutationBody = BodyType<UpdatePreferencesBody>;
export type UpdatePreferencesMutationError = ErrorType<unknown>;

/**
 * @summary Update user preferences
 */
export const useUpdatePreferences = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof updatePreferences>>,
    TError,
    { storeDomain: string; data: BodyType<UpdatePreferencesBody> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationResult<
  Awaited<ReturnType<typeof updatePreferences>>,
  TError,
  { storeDomain: string; data: BodyType<UpdatePreferencesBody> },
  TContext
> => {
  return useMutation(getUpdatePreferencesMutationOptions(options));
};

/**
 * @summary Get analytics data for a store
 */
export const getGetAnalyticsUrl = (
  storeDomain: string,
  params?: GetAnalyticsParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/stores/${storeDomain}/analytics?${stringifiedParams}`
    : `/api/stores/${storeDomain}/analytics`;
};

export const getAnalytics = async (
  storeDomain: string,
  params?: GetAnalyticsParams,
  options?: RequestInit,
): Promise<AnalyticsData> => {
  return customFetch<AnalyticsData>(getGetAnalyticsUrl(storeDomain, params), {
    ...options,
    method: "GET",
  });
};

export const getGetAnalyticsQueryKey = (
  storeDomain: string,
  params?: GetAnalyticsParams,
) => {
  return [
    `/api/stores/${storeDomain}/analytics`,
    ...(params ? [params] : []),
  ] as const;
};

export const getGetAnalyticsQueryOptions = <
  TData = Awaited<ReturnType<typeof getAnalytics>>,
  TError = ErrorType<unknown>,
>(
  storeDomain: string,
  params?: GetAnalyticsParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getAnalytics>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey =
    queryOptions?.queryKey ?? getGetAnalyticsQueryKey(storeDomain, params);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof getAnalytics>>> = ({
    signal,
  }) => getAnalytics(storeDomain, params, { signal, ...requestOptions });

  return {
    queryKey,
    queryFn,
    enabled: !!storeDomain,
    ...queryOptions,
  } as UseQueryOptions<
    Awaited<ReturnType<typeof getAnalytics>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type GetAnalyticsQueryResult = NonNullable<
  Awaited<ReturnType<typeof getAnalytics>>
>;
export type GetAnalyticsQueryError = ErrorType<unknown>;

/**
 * @summary Get analytics data for a store
 */

export function useGetAnalytics<
  TData = Awaited<ReturnType<typeof getAnalytics>>,
  TError = ErrorType<unknown>,
>(
  storeDomain: string,
  params?: GetAnalyticsParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getAnalytics>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
): UseQueryResult<TData, TError> & { queryKey: QueryKey } {
  const queryOptions = getGetAnalyticsQueryOptions(
    storeDomain,
    params,
    options,
  );

  const query = useQuery(queryOptions) as UseQueryResult<TData, TError> & {
    queryKey: QueryKey;
  };

  return { ...query, queryKey: queryOptions.queryKey };
}
